mapper.select:
SELECT COUNT(*)
FROM assistant_recommendation ar
JOIN assistant_recommendation_item ari
  ON ari.recommendation_id = ar.recommendation_id
WHERE ar.recommendation_id = #{recommendationId}
  AND ar.user_id = #{userId}
  AND ari.spu_id = #{spuId}
  AND (#{skuId} IS NULL OR ari.sku_id = #{skuId})
  AND ari.selected = TRUE

SELECT recommendation_id
FROM behavior_event
WHERE user_id = #{userId}
  AND sku_id = #{skuId}
  AND event_type IN ('CART_ADD', 'RECOMMENDATION_CART_ADD')
  AND recommendation_id IS NOT NULL
  AND event_time >= #{since}
ORDER BY event_time DESC, id DESC
LIMIT 1

SELECT recommendation_id
FROM behavior_event
WHERE user_id = #{userId}
  AND order_no = #{orderNo}
  AND sku_id = #{skuId}
  AND event_type = 'ORDER_CREATED'
  AND recommendation_id IS NOT NULL
ORDER BY event_time DESC, id DESC
LIMIT 1
